def _default_workspace() -> str:
    if callable(get_paths):
        try:
            return str(get_paths().runtime_root)
        except Exception:
            pass
    if os.name == "nt":
        return r"D:\code\Runtime\CyberCar_Workspace"
    return str(Path.home() / "CyberCar_Workspace")


