def _default_debug_port() -> int:
    raw = str(os.getenv("CYBERCAR_CHROME_DEBUG_PORT", "9333") or "").strip()
    try:
        value = int(raw)
    except Exception:
        return 9333
    if 1 <= value <= 65535:
        return value
    return 9333


